const body      = $('Listen — Dashboard Submits Form').item.json.body;
const company   = $('Get Company from Airtable').item.json;
const contact   = $('Get Contact from Airtable').item.json;

const pm = body.payment_method;
const freq = body.payment_frequency;
const force = body.force_payment;
const part = body.participant_type;

const payload = {
  test_mode: false,
  template_ids: [body.template_id],
  subject: 'Please sign: ' + (company['DBA Name'] || company['Legal Name'] || ''),
  message: 'Please review and sign the attached document.',
  recipients: [
    {
      id: '1',
      name: contact['Full Name'] || body.contact_name,
      email: contact['Email'] || body.contact_email
    }
  ],
  fields: [
    { api_id: 'Customer_Name',       value: contact['Full Name']          || '' },
    { api_id: 'Customer_Email',      value: contact['Email']              || '' },
    { api_id: 'Company_Name',        value: company['DBA Name']           || '' },
    { api_id: 'Customer_Phone',      value: contact['Phone']              || '' },
    { api_id: 'Customer_Address',    value: company['DBA Street']         || '' },
    { api_id: 'Customer_City',       value: company['DBA City']           || '' },
    { api_id: 'Customer_State',      value: company['DBA State']          || '' },
    { api_id: 'Customer_Zip',        value: company['DBA Zip Code']       || '' },
    { api_id: 'Bank_Name',           value: body.bank_name                || '' },
    { api_id: 'Routing_Number',      value: body.routing_number           || '' },
    { api_id: 'Account_Number',      value: body.account_number           || '' },
    { api_id: 'Payment_Start_Date',  value: body.payment_start_date       || '' },
    { api_id: 'Payment_Amount',      value: String(body.payment_amount)   || '' },
    { api_id: 'Checking',            value: pm === 'Checking'    ? 'true' : 'false' },
    { api_id: 'Savings',             value: pm === 'Savings'     ? 'true' : 'false' },
    { api_id: 'Monthly',             value: freq === 'Monthly'   ? 'true' : 'false' },
    { api_id: 'Quarterly',           value: freq === 'Quarterly' ? 'true' : 'false' },
    { api_id: 'Annually',            value: freq === 'Annually'  ? 'true' : 'false' },
    { api_id: 'Yes',                 value: force === 'Yes'      ? 'true' : 'false' },
    { api_id: 'No',                  value: force === 'No'       ? 'true' : 'false' },
    { api_id: 'New_Participant',     value: part === 'New Participant'        ? 'true' : 'false' },
    { api_id: 'Change_Participant',  value: part === 'Change to Participant'  ? 'true' : 'false' }
  ]
};

return [{ json: payload }];
